UPDATE CLUB_MEMBER
SET CLUB_MBR_WHDWL_DT = SYSDATE
WHERE CLUB_NO = #{clubNo}
  AND EMP_ID = #{empId}
  AND CLUB_MBR_WHDWL_DT IS NULL

UPDATE CLUB_NOTICE
SET CLUB_NTC_CNT = CLUB_NTC_CNT + 1
WHERE CLUB_NTC_NO = #{clubNtcNo}

UPDATE CLUB_NOTICE
SET CLUB_NTC_STTS = 'Y'
WHERE CLUB_NTC_NO = #{clubNtcNo}

mapper.select:
SELECT T.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY B.CLUB_BBS_DT DESC) RNUM , B.CLUB_BBS_NO , B.CLUB_NO , B.CLUB_MBR_NO , B.DEPT_CD , B.CLUB_BBS_TTL , B.CLUB_BBS_CNT , B.CLUB_BBS_DT , B.CLUB_BBS_FILE_NO , E.EMP_NM , E.EMP_JBGD , ( SELECT FD.FILE_DTL_PATH FROM FILE_DETAIL FD WHERE FD.FILE_ID = B.CLUB_BBS_FILE_NO AND ROWNUM = 1 ) AS THUMBNAIL_PATH , ( SELECT COUNT(*) FROM FILE_DETAIL FD WHERE FD.FILE_ID = B.CLUB_BBS_FILE_NO ) AS FILE_CNT FROM CLUB_BOARD B INNER JOIN EMPLOYEE E ON E.EMP_ID = B.CLUB_MBR_NO WHERE B.CLUB_NO = #{clubNo} AND B.CLUB_BBS_STTS = 'N'
AND ( B.CLUB_BBS_TTL LIKE '%' || #{keyword} || '%' OR B.CLUB_BBS_CN LIKE '%' || #{keyword} || '%' OR E.EMP_NM LIKE '%' || #{keyword} || '%' )
) T WHERE RNUM BETWEEN (#{currentPage} * 6) - (5) AND (#{currentPage} * 6)

