SET CLUB_BBS_CNT = CLUB_BBS_CNT + 1
WHERE CLUB_BBS_NO = #{clubBbsNo}

UPDATE CLUB_BOARD
SET CLUB_BBS_STTS = 'Y'
WHERE CLUB_BBS_NO = #{clubBbsNo}
